// OutputTypeContract Structured-output contract for agent replies. When set, Nova OS
// validates every assistant reply against `schema` before return.
// Server-side since v0.1.4.
type OutputTypeContract struct {
	// Schema A subset of JSON Schema Draft 2020-12 used for tool input schemas.
	// Vertex AI rejects `type:array` without `items` — the SDK validator
	// enforces `items` is present everywhere on write.
	Schema JSONSchemaObject `json:"schema"`

	// ViolationMode How to handle a reply that fails validation:
	// - `error` — return HTTP 422 with the violations.
	// - `log` — return the reply as-is plus `output_violations`; partner decides what to do.
	// - `repair` — re-prompt the model once with the schema in the system prompt;
	//   return whichever attempt validates, plus `output_violations` from the first.
	ViolationMode *OutputTypeContractViolationMode `json:"violation_mode,omitempty"`
}

// OutputTypeContractViolationMode How to handle a reply that fails validation:
//   - `error` — return HTTP 422 with the violations.
//   - `log` — return the reply as-is plus `output_violations`; partner decides what to do.
//   - `repair` — re-prompt the model once with the schema in the system prompt;
//     return whichever attempt validates, plus `output_violations` from the first.
type OutputTypeContractViolationMode string

